const $ = window.jQuery;
import ExtractAjaxVars from "../utils/ExtractAjaxVars";

WplkConfig.prototype.init = function () {
    this.read_from_dom();
}

/**
 * Load the config from the DOM element script tag.
 */
WplkConfig.prototype.read_from_dom = function () {
    this.config = ExtractAjaxVars($('#wplk-config'));
    this.config.post_types = this.config.post_types || [];
}

WplkConfig.prototype.hierarchical_post_types = function (exclude = []) {
    return $.map(this.config.post_types, (type, i) => {
        // Allow us to exclude items by name.
        if (exclude && $.inArray(type.type, exclude) > -1) {
            return null;
        }

        // If not hierarchical, ignore it.
        if (!type.hierarchical) {
            return null;
        }

        // Return just the type name.
        return type.type;
    });
}

WplkConfig.prototype.is_post_type_hierarchical = function (post_type) {
    let names = this.hierarchical_post_types();
    return names.indexOf(post_type) > -1;
}

WplkConfig.prototype.is_add_new_domain_page = function() {
    return $('body.post-type-mapped-domain').hasClass( 'post-new-php' );
}

function WplkConfig() {
    this.config = {};
}

export default new WplkConfig