import select2 from 'select2'
import WplkMappingRow from "./objects/WplkMappingRow";
import WplkConfig from "./objects/WplkConfig";


(function ($, window, document, undefined) {

    $(function () {

        const $ui = $('.WplkMappings');
        if (!$ui.length) {
            return;
        }

        WplkConfig.init();

        const $title = $('#title');
        $title.on('keyup', () => $(window).trigger('wplk/domain_changed', $title.val()));

        const $sortables_container = $ui.find('.WplkMappings__sortable');

        /**
         * Toggle the visibility — using jQuery's `hide` and `show` methods — of the select field's parent. If you use
         * this on anything other than a select2 field wrapped in a containing element, you might get upset. It's ok to
         * shed a tear over code now and then. Just be sure to pick yourself back up and
         *
         * @param state 'hide' || 'show'
         * @returns {*}
         */
        $.fn.wplkSelect2Visibility = function (state) {
            if (state !== 'hide' && state !== 'show') {
                return this;
            }
            return this.each(function () {
                //$.fn[state].call($(this).next('.select2-container'));
                $.fn[state].call($(this).parent());
            });
        };

        // Instantiate any mapping rows in the DOM on page load.
        $ui.find('.WplkMapping').each((i, element) => WplkMappingRow.prototype.make($(element)).init());

        // Enable drag n drop sorting of mapping rows.
        $sortables_container.sortable({
            items: '.WplkMapping',
            handle: '.WplkMapping__icon',
            placeholder: 'WplkMapping--placeholder',
            opacity: 0.8,
            forcePlaceholderSize: true,
        });

        // Handle new mapping generation.
        $ui.find('.WplkMappings__action-add-mapping').on('click', () => {
            const $row = $(WplkMappingRow.prototype.tpl({
                domain: $title.val(),
            }));
            const instance = WplkMappingRow.prototype.make($row);
            instance.init();
            $sortables_container.append($row);
            instance.toggle_panel();
        });
    });

    // Image upload field.
    $(function () {

        $('.WplkField__image').each((index, element) => {
            let $this = $(element);
            let $select = $this.find('.WplkField__image-select');
            let $remove = $this.find('.WplkField__image-remove');
            let $preview = $this.find('.WplkField__image-preview');
            let $image = $this.find('.WplkField__image-img');
            let $id = $this.find('.WplkField__image-id');
            let $not_selected = $this.find('.WplkField__image-not-selected');
            let size = 512;

            function calculateImageSelectOptions( attachment ) {
                var realWidth = attachment.get( 'width' ),
                    realHeight = attachment.get( 'height' ),
                    xInit = 512,
                    yInit = 512,
                    ratio = xInit / yInit,
                    xImg = xInit,
                    yImg = yInit,
                    x1,
                    y1,
                    imgSelectOptions;

                if ( realWidth / realHeight > ratio ) {
                    yInit = realHeight;
                    xInit = yInit * ratio;
                } else {
                    xInit = realWidth;
                    yInit = xInit / ratio;
                }

                x1 = ( realWidth - xInit ) / 2;
                y1 = ( realHeight - yInit ) / 2;

                imgSelectOptions = {
                    aspectRatio: xInit + ':' + yInit,
                    handles: true,
                    keys: true,
                    instance: true,
                    persistent: true,
                    imageWidth: realWidth,
                    imageHeight: realHeight,
                    minWidth: xImg > xInit ? xInit : xImg,
                    minHeight: yImg > yInit ? yInit : yImg,
                    x1: x1,
                    y1: y1,
                    x2: xInit + x1,
                    y2: yInit + y1,
                };

                return imgSelectOptions;
            }

            let settings = $.extend(
                {
                    button_text: 'Select',
                    title: 'Select or Upload Media',
                },
                $this.data('settings') || {}
            );

            // Open the modal when the button is clicked.
            $select.on('click', (e) => {
                e.preventDefault();
                var frame = wp.media({
                    button: {
                        // Set the text of the button.
                        text: settings.button_text,
                        // Don't close, we might need to crop.
                        close: false,
                    },
                    states: [
                        new wp.media.controller.Library({
                            title: settings.title,
                            library: wp.media.query( { type: 'image' } ),
                            date: false,
                            suggestedWidth: size,
                            suggestedHeight: size,
                        } ),
                        new wp.media.controller.SiteIconCropper({
                            control: {
                                params: {
                                    width: size,
                                    height: size,
                                },
                            },
                            imgSelectOptions: calculateImageSelectOptions,
                        } ),
                    ],
                } );

                frame.on( 'cropped', function ( attachment ) {
                    let preview = ( attachment.sizes.thumbnail && attachment.sizes.thumbnail.url ) || attachment.sizes.full.url;
                    $image.attr('src', preview);
                    $id.val(attachment.id);
                    $not_selected.hide();
                    $preview.show();
                    frame.close();
                } );

                // Set the UI elements when an image is selected.
                frame.on('select', () => {
                    let selection = frame.state('').get('selection').first();
                    let attachment = frame.state('').get('selection').first().toJSON();
                    let attachment_id = attachment.id;
                    let preview = ( attachment.sizes.thumbnail && attachment.sizes.thumbnail.url ) || attachment.sizes.full.url;

                    if( selection.attributes.height === size && size === selection.attributes.width ){
                        $image.attr('src', preview);
                        $id.val(attachment_id);
                        $not_selected.hide();
                        $preview.show();
                        frame.close();
                    } else {
                        frame.setState( 'cropper' );
                    }
                });
                frame.open();
            });

            // Remove the image preview and ID when the remove icon is clicked.
            $remove.on('click', (e) => {
                e.preventDefault();
                $image.attr('src', $image.data('src-empty'));
                $id.val(0);
                $not_selected.show();
                $preview.hide();
            });
        });
    })

    $(function () {
        const connectionStatus = $('#wplk-mapping-status');

        if (!connectionStatus.length || connectionStatus.val() === 'connected') {
            return;
        }

        const recordTypeSelect = $('#wplk-mapping-record-type');
        const infoARecord = $('.wplk-mapping-info-a-record');
        const infoCnameRecord = $('.wplk-mapping-info-cname-record');
        const recordHost = $('#wplk-mapping-host');
        const recordIP = $('#wplk-mapping-ip');
        const initialRecordIPValue = recordIP.val();
        const testButton = $('#wplk-mapping-test');

        const toggleInfo = () => {
            const recordType = recordTypeSelect.val();
            const isARecord = recordType === 'a';
            infoARecord.toggle(isARecord);
            infoCnameRecord.toggle(!isARecord);
            recordHost.val(isARecord ? '@' : 'blog');
            recordIP.val(isARecord ? initialRecordIPValue : 'https://demo.com/blog/');
        };

        // Initialize visibility on page load
        toggleInfo();

        const addNotice = (title, message, type) => {
            const notices = $('.WplkNotices');
            const notice = $(`
            <div class="WplkNotice WplkNotice__removable WplkNotice__${type}">
                <p><strong>${title}</strong></p>
                <p>${message}</p>
            </div>
            `);
            notices.empty().append(notice); // Clear existing notices and append new one
        };

        const testConnection = () => {
            if (testButton.prop('disabled')) {
                return;
            }

            const { request } = testButton.data();

            testButton.addClass('button-disabled').prop('disabled', true);
            testButton.prepend('<span class="dashicons dashicons-update"></span>');

            $.ajax({
                url: request.url,
                type: 'POST',
                data: {
                    nonce: request.vars.nonce,
                    domain: request.domain,
                    post_id: request.post_id,
                },
                success: (response) => {
                    const noticeType = response.success ? 'success' : 'error';
                    addNotice(response.success ? 'Success!' : 'Connection failed', response.message, noticeType);
                },
                error: () => {
                    addNotice('Connection failed', 'An error occurred while testing the connection.', 'error');
                },
                complete: () => {
                    testButton.removeClass('button-disabled').prop('disabled', false);
                    testButton.find('.dashicons').remove();
                },
            });
        };

        if (connectionStatus.val() === 'failed') {
            testConnection();
        }

        recordTypeSelect.on('change', toggleInfo);
        testButton.on('click', testConnection);
    });

    // Legacy JS — remove asap
    $(function () {

        // if our data block is not available, don't do anything
        var $myData = $('#wp_landing_kit_fetch_mappable_domains');
        if (!$myData.length)
            return;

        let data = {};

        // attempt to parse the content of our data block
        try {
            data = JSON.parse($myData.text());
        } catch (err) { // invalid json
            return;
        }

        let $mapped_page_select = $('#mapped-domain-id');

        if ($mapped_page_select.length) {
            init_select2_page_select();
        }

        /**
         * Initialise the select2 library AJAX search for the mapped domain post select field.
         */
        function init_select2_page_select() {
            $mapped_page_select.select2({
                minimumInputLength: 3,
                allowClear: true,
                placeholder: 'Choose a domain for this post',
                ajax: {
                    url: data.ajax_url,
                    dataType: 'json',
                    delay: 250,
                    cache: true,
                    data: (params) => {
                        return {
                            q: params.term,
                            action: data.action,
                            _wpnonce: data.nonce,
                            domain_id: data.domain_id,
                            selected_id: data.selected_id || 0,
                        };
                    },
                    processResults: (response) => {
                        const options = [];

                        if (response.matches) {
                            $.each(response.matches, (index, post) => {
                                options.push({
                                    id: post.post_id,
                                    text: post.title,
                                    mapped_post: post.mapped_post,
                                    disabled: !!post.mapped_post,
                                });
                            });

                        }
                        return {
                            results: options
                        };
                    },
                },
                templateResult: (state) => {
                    let $opt = $(`<div class="WplkOption"><span class="WplkOption__title">${state.text}</span></div>`);

                    if (state.mapped_post) {
                        $opt.append($(`<span class="WplkOption__mapped-domain-note">&nbsp;&nbsp;(mapped to ${state.mapped_post})</span>`))
                    }
                    return $opt;
                }
            });
        }

    });
    // eof Legacy JS

})(jQuery, window, document);